import java.util.*;
public class RandSet {
    static class RandomizedSet {
        Map<Integer,Integer> map=new HashMap<>(); List<Integer> list=new ArrayList<>(); Random rnd=new Random();
        boolean insert(int v){if(map.containsKey(v))return false;map.put(v,list.size());list.add(v);return true;}
        boolean remove(int v){if(!map.containsKey(v))return false;
            int idx=map.get(v),last=list.get(list.size()-1);
            list.set(idx,last);map.put(last,idx);list.remove(list.size()-1);map.remove(v);return true;}
        int getRandom(){return list.get(rnd.nextInt(list.size()));}
    }
    public static void main(String[] a){
        RandomizedSet rs=new RandomizedSet();
        System.out.println(rs.insert(1)); // true
        System.out.println(rs.remove(2)); // false
        System.out.println(rs.insert(2)); // true
        boolean r=rs.getRandom()==1||rs.getRandom()==2;System.out.println(r); // true
        System.out.println("O(1) insert/remove/getRandom — HashMap+ArrayList swap trick");
    }
}

import java.util.*;
public class LRUCache2 {
    static class LRU {
        class N{int k,v;N p,n;N(int k,int v){this.k=k;this.v=v;}}
        Map<Integer,N> m=new HashMap<>();N h=new N(0,0),t=new N(0,0);int c;
        LRU(int cap){c=cap;h.n=t;t.p=h;}
        void rm(N n){n.p.n=n.n;n.n.p=n.p;}void af(N n){n.n=h.n;n.p=h;h.n.p=n;h.n=n;}
        int get(int k){if(!m.containsKey(k))return -1;N n=m.get(k);rm(n);af(n);return n.v;}
        void put(int k,int v){if(m.containsKey(k)){N n=m.get(k);n.v=v;rm(n);af(n);return;}if(m.size()==c){m.remove(t.p.k);rm(t.p);}N n=new N(k,v);af(n);m.put(k,n);}
    }
    public static void main(String[] a){LRU l=new LRU(2);l.put(1,1);l.put(2,2);System.out.println(l.get(1));l.put(3,3);System.out.println(l.get(2));System.out.println(l.get(3));System.out.println("O(1) get+put: HashMap lookup + DLL reorder");}
}

import java.util.*;
public class MySet {
    List<Integer>[] buckets=(List<Integer>[])new List[128];
    int hash(int k){return Math.abs(k)%128;}
    boolean add(int k){int h=hash(k);if(buckets[h]==null)buckets[h]=new ArrayList<>();if(buckets[h].contains(k))return false;buckets[h].add(k);return true;}
    boolean contains(int k){int h=hash(k);return buckets[h]!=null&&buckets[h].contains(k);}
    boolean remove(int k){int h=hash(k);if(buckets[h]==null)return false;return buckets[h].remove(Integer.valueOf(k));}
    public static void main(String[] a){MySet s=new MySet();System.out.println(s.add(1));System.out.println(s.add(2));System.out.println(s.contains(1));System.out.println(s.remove(2));System.out.println(s.contains(2));System.out.println("Chaining HashSet: O(1) avg — bucket list for collision handling");}
}

import java.util.*;
public class InsDelRand {
    Map<Integer,Integer> idx=new HashMap<>();List<Integer> list=new ArrayList<>();Random r=new Random();
    boolean insert(int v){if(idx.containsKey(v))return false;idx.put(v,list.size());list.add(v);return true;}
    boolean delete(int v){if(!idx.containsKey(v))return false;
        int i=idx.get(v),last=list.get(list.size()-1);
        list.set(i,last);idx.put(last,i);list.remove(list.size()-1);idx.remove(v);return true;}
    int getRandom(){return list.get(r.nextInt(list.size()));}
    public static void main(String[] a){InsDelRand s=new InsDelRand();s.insert(1);s.insert(2);s.insert(3);System.out.println(s.delete(2));System.out.println(s.getRandom()!=2);System.out.println("Swap-with-last: O(1) delete from ArrayList by avoiding O(n) shift");}
}

import java.util.*;
public class WordFreq {
    public static String[] topKWords(String[] words, int k) {
        Map<String,Integer> freq=new HashMap<>();for(String w:words)freq.merge(w,1,Integer::sum);
        PriorityQueue<String> pq=new PriorityQueue<>((a,b)->freq.get(a).equals(freq.get(b))?b.compareTo(a):freq.get(a)-freq.get(b));
        for(String w:freq.keySet()){pq.offer(w);if(pq.size()>k)pq.poll();}
        String[] res=new String[k];for(int i=k-1;i>=0;i--)res[i]=pq.poll();return res;
    }
    public static void main(String[] a){
        System.out.println(Arrays.toString(topKWords(new String[]{"i","love","leetcode","i","love","coding"},2)));
        System.out.println(Arrays.toString(topKWords(new String[]{"the","day","is","sunny","the","the","the","sunny","is","is"},4)));
        System.out.println("O(n log k) — freq map + min-heap (lex ascending for ties)");
    }
}

import java.util.*;
public class LFU {
    Map<Integer,Integer> kv=new HashMap<>(),kf=new HashMap<>();Map<Integer,LinkedHashSet<Integer>> fk=new HashMap<>();int cap,minF;
    LFU(int c){cap=c;}
    void upd(int k){int f=kf.get(k);kf.put(k,f+1);fk.computeIfAbsent(f,x->new LinkedHashSet<>()).remove(k);if(fk.get(f).isEmpty()&&f==minF)minF++;fk.computeIfAbsent(f+1,x->new LinkedHashSet<>()).add(k);}
    int get(int k){if(!kv.containsKey(k))return -1;upd(k);return kv.get(k);}
    void put(int k,int v){if(cap==0)return;if(kv.containsKey(k)){kv.put(k,v);upd(k);return;}if(kv.size()==cap){int e=fk.get(minF).iterator().next();fk.get(minF).remove(e);kv.remove(e);kf.remove(e);}kv.put(k,v);kf.put(k,1);fk.computeIfAbsent(1,x->new LinkedHashSet<>()).add(k);minF=1;}
    public static void main(String[] a){LFU l=new LFU(2);l.put(1,1);l.put(2,2);System.out.println(l.get(1));l.put(3,3);System.out.println(l.get(2));System.out.println(l.get(3));System.out.println("O(1) all ops: kv+kf+fk(LinkedHashSet for LRU within freq)");}
}

import java.util.*;
public class SnapArr {
    List<TreeMap<Integer,Integer>> d=new ArrayList<>();int sid=0;
    SnapArr(int n){for(int i=0;i<n;i++){TreeMap<Integer,Integer> m=new TreeMap<>();m.put(0,0);d.add(m);}}
    void set(int i,int v){d.get(i).put(sid,v);}
    int snap(){return sid++;}
    int get(int i,int snap_id){return d.get(i).floorEntry(snap_id).getValue();}
    public static void main(String[] a){SnapArr sa=new SnapArr(3);sa.set(0,5);System.out.println(sa.snap());sa.set(0,6);System.out.println(sa.get(0,0));System.out.println(sa.get(0,1));System.out.println("TreeMap+floorEntry: binary search for snap_id. O(log s) get, O(log s) set");}
}

import java.util.*;
public class DesignHM {
    private static final int BUCKETS=1024;
    List<int[]>[] table=(List<int[]>[])new List[BUCKETS];
    int hash(int k){return k%BUCKETS;}
    void put(int k,int v){int h=hash(k);if(table[h]==null)table[h]=new ArrayList<>();for(int[] p:table[h])if(p[0]==k){p[1]=v;return;}table[h].add(new int[]{k,v});}
    int get(int k){int h=hash(k);if(table[h]==null)return -1;for(int[] p:table[h])if(p[0]==k)return p[1];return -1;}
    void remove(int k){int h=hash(k);if(table[h]!=null)table[h].removeIf(p->p[0]==k);}
    public static void main(String[] a){DesignHM hm=new DesignHM();hm.put(1,1);hm.put(2,2);System.out.println(hm.get(1));System.out.println(hm.get(3));hm.put(2,1);System.out.println(hm.get(2));hm.remove(2);System.out.println(hm.get(2));System.out.println("Chaining with 1024 buckets: O(1) avg, O(n/1024) worst with good hash");}
}

import java.util.*;
public class TinyURL {
    Map<String,String> enc=new HashMap<>(),dec=new HashMap<>();int id=0;
    static final String BASE="http://tinyurl.com/";
    String encode(String longUrl){String key=BASE+(id++);enc.put(longUrl,key);dec.put(key,longUrl);return key;}
    String decode(String shortUrl){return dec.get(shortUrl);}
    public static void main(String[] a){TinyURL t=new TinyURL();String short1=t.encode("https://leetcode.com/problems/design-tinyurl");System.out.println(short1.startsWith("http://tinyurl.com/"));System.out.println(t.decode(short1).equals("https://leetcode.com/problems/design-tinyurl"));System.out.println("Two maps: url→short and short→url. O(1) encode/decode");}
}

import java.util.*;
public class TimeMap {
    Map<String,TreeMap<Integer,String>> store=new HashMap<>();
    void set(String k,String v,int ts){store.computeIfAbsent(k,x->new TreeMap<>()).put(ts,v);}
    String get(String k,int ts){if(!store.containsKey(k))return "";Map.Entry<Integer,String> e=store.get(k).floorEntry(ts);return e==null?"":e.getValue();}
    public static void main(String[] a){TimeMap tm=new TimeMap();tm.set("foo","bar",1);System.out.println(tm.get("foo",1));System.out.println(tm.get("foo",3));tm.set("foo","bar2",4);System.out.println(tm.get("foo",4));System.out.println(tm.get("foo",5));System.out.println("HashMap<key,TreeMap<ts,val>>: O(log n) get, O(log n) set");}
}

import java.util.*;
public class HashSynth {
    static class RS{Map<Integer,Integer> idx=new HashMap<>();List<Integer> l=new ArrayList<>();Random r=new Random();boolean ins(int v){if(idx.containsKey(v))return false;idx.put(v,l.size());l.add(v);return true;}boolean del(int v){if(!idx.containsKey(v))return false;int i=idx.get(v),la=l.get(l.size()-1);l.set(i,la);idx.put(la,i);l.remove(l.size()-1);idx.remove(v);return true;}int rand(){return l.get(r.nextInt(l.size()));}}
    public static void main(String[] a){
        RS rs=new RS();rs.ins(1);rs.ins(2);rs.ins(3);rs.del(2);
        boolean ok=!rs.idx.containsKey(2)&&rs.l.size()==2;
        System.out.println("RandomizedSet del(2)="+rs.del(2)+" after already deleted: "+!rs.idx.containsKey(2));
        System.out.println("size: "+rs.l.size()); // 2
        System.out.println("All pass: "+ok);
    }
}

